<?php/** * WooCommerce integration for AquaLuxe Theme * * @package AquaLuxe *//** * WooCommerce setup function. */function aqualuxe_woocommerce_setup() {    // Add theme support for WooCommerce features    add_theme_support( 'woocommerce' );    add_theme_support( 'wc-product-gallery-zoom' );    add_theme_support( 'wc-product-gallery-lightbox' );    add_theme_support( 'wc-product-gallery-slider' );}add_action( 'after_setup_theme', 'aqualuxe_woocommerce_setup' );/** * Disable the default WooCommerce stylesheet. */function aqualuxe_dequeue_woocommerce_styles() {    // If we're not on a WooCommerce page, don't dequeue    if ( ! is_woocommerce() && ! is_cart() && ! is_checkout() && ! is_account_page() ) {        return;    }    // Dequeue the default WooCommerce stylesheet    wp_dequeue_style( 'woocommerce-general' );    wp_dequeue_style( 'woocommerce-layout' );    wp_dequeue_style( 'woocommerce-smallscreen' );}add_action( 'wp_enqueue_scripts', 'aqualuxe_dequeue_woocommerce_styles', 99 );/** * Add 'woocommerce-active' class to the body tag. * * @param array $classes CSS classes applied to the body tag. * @return array $classes modified to include 'woocommerce-active' class. */function aqualuxe_woocommerce_active_body_class( $classes ) {    $classes[] = 'woocommerce-active';    return $classes;}add_filter( 'body_class', 'aqualuxe_woocommerce_active_body_class' );/** * Related Products Args. * * @param array $args related products args. * @return array $args related products args. */function aqualuxe_woocommerce_related_products_args( $args ) {    $defaults = array(        'posts_per_page' => 3,        'columns'        => 3,    );    $args = wp_parse_args( $defaults, $args );    return $args;}add_filter( 'woocommerce_output_related_products_args', 'aqualuxe_woocommerce_related_products_args' );/** * Remove default WooCommerce wrapper. */remove_action( 'woocommerce_before_main_content', 'woocommerce_output_content_wrapper', 10 );remove_action( 'woocommerce_after_main_content', 'woocommerce_output_content_wrapper_end', 10 );/** * Add custom WooCommerce wrapper. */function aqualuxe_woocommerce_wrapper_before() {    ?>    <main id="primary" class="site-main container mx-auto px-4 py-8">    <?php}add_action( 'woocommerce_before_main_content', 'aqualuxe_woocommerce_wrapper_before' );/** * Add custom WooCommerce wrapper end. */function aqualuxe_woocommerce_wrapper_after() {    ?>    </main><!-- #main -->    <?php}add_action( 'woocommerce_after_main_content', 'aqualuxe_woocommerce_wrapper_after' );/** * Change number of products per row */function aqualuxe_woocommerce_loop_columns() {    return get_theme_mod( 'aqualuxe_products_per_row', 3 );}add_filter( 'loop_shop_columns', 'aqualuxe_woocommerce_loop_columns' );/** * Change number of products per page */function aqualuxe_woocommerce_products_per_page() {    return get_theme_mod( 'aqualuxe_products_per_page', 12 );}add_filter( 'loop_shop_per_page', 'aqualuxe_woocommerce_products_per_page' );/** * Adjust product grid item classes */function aqualuxe_woocommerce_product_loop_classes() {    return 'bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden transition-shadow duration-300 hover:shadow-lg';}add_filter( 'woocommerce_product_loop_start', 'aqualuxe_woocommerce_product_loop_start', 10 );/** * Adjust product loop start */function aqualuxe_woocommerce_product_loop_start( $loop_start ) {    $columns = aqualuxe_woocommerce_loop_columns();    return '<ul class="products grid grid-cols-1 sm:grid-cols-2 md:grid-cols-' . esc_attr( $columns ) . ' gap-6">';}/** * Add custom classes to product items */function aqualuxe_woocommerce_product_classes( $classes, $product ) {    $classes[] = 'bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden transition-shadow duration-300 hover:shadow-lg';    return $classes;}add_filter( 'woocommerce_post_class', 'aqualuxe_woocommerce_product_classes', 10, 2 );/** * Remove default WooCommerce pagination */remove_action( 'woocommerce_after_shop_loop', 'woocommerce_pagination', 10 );/** * Add custom pagination */function aqualuxe_woocommerce_pagination() {    ?>    <nav class="woocommerce-pagination mt-8">        <?php        echo paginate_links(            apply_filters(                'woocommerce_pagination_args',                array(                    'prev_text' => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="feather feather-arrow-left"><line x1="19" y1="12" x2="5" y2="12"></line><polyline points="12 19 5 12 12 5"></polyline></svg> ' . esc_html__( 'Previous', 'aqualuxe' ),                    'next_text' => esc_html__( 'Next', 'aqualuxe' ) . ' <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="feather feather-arrow-right"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>',                    'type'      => 'list',                    'end_size'  => 3,                    'mid_size'  => 3,                )            )        );        ?>    </nav>    <?php}add_action( 'woocommerce_after_shop_loop', 'aqualuxe_woocommerce_pagination', 10 );/** * Customize sale flash badge */function aqualuxe_woocommerce_sale_flash() {    return '<span class="onsale absolute top-4 left-4 bg-red-600 text-white text-xs font-bold uppercase py-1 px-2 rounded z-10">' . esc_html__( 'Sale!', 'aqualuxe' ) . '</span>';}add_filter( 'woocommerce_sale_flash', 'aqualuxe_woocommerce_sale_flash' );/** * Customize product thumbnail wrapper */function aqualuxe_woocommerce_template_loop_product_thumbnail() {    global $product;        echo '<div class="product-thumbnail relative overflow-hidden group">';    echo '<a href="' . esc_url( get_permalink() ) . '">';    echo woocommerce_get_product_thumbnail( 'woocommerce_thumbnail' );        // Show second image on hover if available    $attachment_ids = $product->get_gallery_image_ids();    if ( $attachment_ids && isset( $attachment_ids[0] ) ) {        echo wp_get_attachment_image( $attachment_ids[0], 'woocommerce_thumbnail', false, array(            'class' => 'product-thumbnail-hover absolute top-0 left-0 w-full h-full object-cover opacity-0 group-hover:opacity-100 transition-opacity duration-300',        ) );    }        echo '</a>';        // Quick view button if enabled    if ( get_theme_mod( 'aqualuxe_quick_view', true ) ) {        echo '<div class="product-actions absolute bottom-0 left-0 w-full p-4 bg-gradient-to-t from-black to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300">';        echo '<button class="quick-view-btn bg-white hover:bg-gray-100 text-gray-800 text-xs font-bold py-2 px-3 rounded" data-product-id="' . esc_attr( $product->get_id() ) . '">' . esc_html__( 'Quick View', 'aqualuxe' ) . '</button>';        echo '</div>';    }        echo '</div>';}remove_action( 'woocommerce_before_shop_loop_item_title', 'woocommerce_template_loop_product_thumbnail', 10 );add_action( 'woocommerce_before_shop_loop_item_title', 'aqualuxe_woocommerce_template_loop_product_thumbnail', 10 );/** * Customize product title */function aqualuxe_woocommerce_template_loop_product_title() {    echo '<h2 class="woocommerce-loop-product__title text-lg font-semibold mb-2 text-gray-900 dark:text-gray-100 hover:text-primary-600 dark:hover:text-primary-400 transition-colors duration-300">' . get_the_title() . '</h2>';}remove_action( 'woocommerce_shop_loop_item_title', 'woocommerce_template_loop_product_title', 10 );add_action( 'woocommerce_shop_loop_item_title', 'aqualuxe_woocommerce_template_loop_product_title', 10 );/** * Customize product price */function aqualuxe_woocommerce_template_loop_price() {    global $product;        if ( $price_html = $product->get_price_html() ) {        echo '<span class="price text-primary-600 dark:text-primary-400 font-bold">' . $price_html . '</span>';    }}remove_action( 'woocommerce_after_shop_loop_item_title', 'woocommerce_template_loop_price', 10 );add_action( 'woocommerce_after_shop_loop_item_title', 'aqualuxe_woocommerce_template_loop_price', 10 );/** * Customize add to cart button */function aqualuxe_woocommerce_loop_add_to_cart_link( $html, $product, $args ) {    $html = sprintf(        '<a href="%s" data-quantity="%s" class="%s mt-3 inline-block bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium py-2 px-4 rounded transition-colors duration-300" %s>%s</a>',        esc_url( $product->add_to_cart_url() ),        esc_attr( isset( $args['quantity'] ) ? $args['quantity'] : 1 ),        esc_attr( isset( $args['class'] ) ? $args['class'] : 'button' ),        isset( $args['attributes'] ) ? wc_implode_html_attributes( $args['attributes'] ) : '',        esc_html( $product->add_to_cart_text() )    );    return $html;}add_filter( 'woocommerce_loop_add_to_cart_link', 'aqualuxe_woocommerce_loop_add_to_cart_link', 10, 3 );